The enableExtensionDeveloperMode function opens a new tab to chrome://extensions/ on every launch of dev:browser. Since the profile is persistent in .playwright-profile, this only needs to happen once. You can check the current configuration before attempting to update it to avoid unnecessary tab flickers. Additionally, ensure that console watchers are attached to the context immediately after launchPersistentContext returns to capture early boot-time errors.

```typescript
async function enableExtensionDeveloperMode(
  context: Awaited<ReturnType<typeof chromium.launchPersistentContext>>
): Promise<void> {
  const page = await context.newPage()
  try {
    await page.goto('chrome://extensions/')
    await page.evaluate(
      () =>
        new Promise<void>((resolve, reject) => {
          const api = (globalThis as any).chrome?.developerPrivate
          if (!api) {
            reject(new Error('chrome.developerPrivate not available'))
            return
          }
          api.getProfileConfiguration((config: any) => {
            if (config.inDeveloperMode) {
              resolve()
            } else {
              api.updateProfileConfiguration({ inDeveloperMode: true }, () => {
                const err = (globalThis as any).chrome.runtime?.lastError
                if (err) reject(new Error(err.message))
                else resolve()
              })
            }
          })
        })
    )
  } catch (err) {
    console.warn('Could not enable extension developer mode:', err instanceof Error ? err.message : err)
  } finally {
    await page.close().catch(() => undefined)
  }
}
```

